   134→pub fn cmd_factory_install(cards_root: &Path) -> anyhow::Result<()> {
   135→    // Resolve repo root (cards_root is .cards, parent is repo)
   136→    let repo_root = fs::canonicalize(cards_root)
   137→        .unwrap_or_else(|_| cards_root.to_path_buf())
   138→        .parent()
   139→        .map(|p| p.to_path_buf())
   140→        .unwrap_or_else(|| PathBuf::from("."));
   141→
   142→    // Use cards_root's parent if cards_root ends with ".cards"
   143→    let repo_root = if cards_root
   144→        .file_name()
   145→        .map(|f| f == ".cards")
   146→        .unwrap_or(false)
   147→    {
   148→        cards_root.parent().unwrap_or(Path::new(".")).to_path_buf()
   149→    } else {
   150→        repo_root
   151→    };
   152→    let repo_root = fs::canonicalize(&repo_root).unwrap_or(repo_root);
   153→
   154→    let la_dir = launchd_dir();
   155→    fs::create_dir_all(&la_dir)?;
   156→
   157→    for (label, subcmd) in &FACTORY_LABELS {
   158→        let plist = generate_plist(label, subcmd, &repo_root);
   159→        let dest = plist_path(label);
   160→        fs::write(&dest, &plist)?;
   161→        println!("✓ wrote {}", dest.display());
   162→    }
   163→
   164→    // Load both
   165→    for (label, _) in &FACTORY_LABELS {
   166→        let dest = plist_path(label);
   167→        let out = StdCommand::new("launchctl")
   168→            .args(["load", "-w"])
   169→            .arg(&dest)
   170→            .output()?;
   171→        if out.status.success() {
   172→            println!("✓ loaded {}", label);
   173→        } else {
   174→            let err = String::from_utf8_lossy(&out.stderr);
   175→            eprintln!("⚠ load {}: {}", label, err.trim());
   176→        }
   177→    }
   178→
   179→    // Icons watcher: default on, same lifecycle as factory
   180→    if cfg!(target_os = "macos") {
   181→        match cmd_icons_install(cards_root) {
   182→            Ok(_) => {}
   183→            Err(e) => eprintln!("⚠ icon watcher: {}", e),
   184→        }
   185→    }
   186→
   187→    // Zellij plugin
   188→    let wasm_src = zellij_plugin_src(&repo_root);
   189→    if wasm_src.exists() {
   190→        let dest = zellij_plugin_dest();
   191→        if let Some(parent) = dest.parent() {
   192→            let _ = fs::create_dir_all(parent);
   193→        }
   194→        match fs::copy(&wasm_src, &dest) {
   195→            Ok(_) => println!("✓ zellij plugin installed: {}", dest.display()),
   196→            Err(e) => eprintln!("  zellij plugin copy failed: {}", e),
   197→        }
   198→    } else {
   199→        println!(
   200→            "  (zellij plugin wasm not built — skipping)\n  build with: cargo build --manifest-path crates/bop-zellij-plugin/Cargo.toml --target wasm32-wasip1 --release"
   201→        );
   202→    }
   203→
   204→    println!("\nFactory services installed. Run `bop factory status` to verify.");
   205→    Ok(())
   206→}
