    20→/// Stamp icons for all state dirs + cards within a single team root.
    21→/// Terminal-state cards also get compression refreshed.
    22→pub fn sync_icons_in_root(
    23→    team_root: &Path,
    24→    n_cards: &mut usize,
    25→    n_dirs: &mut usize,
    26→    n_terminal_cards: &mut usize,
    27→) {
    28→    const STATES: &[&str] = &[
    29→        "drafts",
    30→        "pending",
    31→        "running",
    32→        "done",
    33→        "merged",
    34→        "failed",
    35→        "templates",
    36→    ];
    37→    for &state in STATES {
    38→        let dir = team_root.join(state);
    39→        if !dir.exists() {
    40→            continue;
    41→        }
    42→        // State directory itself gets an icon.
    43→        set_card_icon(&dir);
    44→        *n_dirs += 1;
    45→        // Each .bop inside gets an icon.
    46→        if let Ok(entries) = fs::read_dir(&dir) {
    47→            for entry in entries.flatten() {
    48→                let path = entry.path();
    49→                if path.extension().and_then(|e| e.to_str()) == Some("bop") && path.is_dir() {
    50→                    set_card_icon(&path);
    51→                    quicklook::sync_card_action_links(&path);
    52→                    if matches!(
    53→                        quicklook::card_state_from_path(&path).as_deref(),
    54→                        Some("done" | "failed" | "merged")
    55→                    ) {
    56→                        quicklook::compress_card(&path);
    57→                        *n_terminal_cards += 1;
    58→                    }
    59→                    *n_cards += 1;
    60→                }
    61→            }
    62→        }
    63→    }
    64→}
