   133→pub fn cmd_factory_install(cards_root: &Path) -> anyhow::Result<()> {
   134→    // Resolve repo root (cards_root is .cards, parent is repo)
   135→    let repo_root = fs::canonicalize(cards_root)
   136→        .unwrap_or_else(|_| cards_root.to_path_buf())
   137→        .parent()
   138→        .map(|p| p.to_path_buf())
   139→        .unwrap_or_else(|| PathBuf::from("."));
   140→
   141→    // Use cards_root's parent if cards_root ends with ".cards"
   142→    let repo_root = if cards_root
   143→        .file_name()
   144→        .map(|f| f == ".cards")
   145→        .unwrap_or(false)
   146→    {
   147→        cards_root.parent().unwrap_or(Path::new(".")).to_path_buf()
   148→    } else {
   149→        repo_root
   150→    };
   151→    let repo_root = fs::canonicalize(&repo_root).unwrap_or(repo_root);
   152→
   153→    let la_dir = launchd_dir();
   154→    fs::create_dir_all(&la_dir)?;
   155→
   156→    for (label, subcmd) in &FACTORY_LABELS {
   157→        let plist = generate_plist(label, subcmd, &repo_root);
   158→        let dest = plist_path(label);
   159→        fs::write(&dest, &plist)?;
   160→        println!("✓ wrote {}", dest.display());
   161→    }
   162→
   163→    // Load both
   164→    for (label, _) in &FACTORY_LABELS {
   165→        let dest = plist_path(label);
   166→        let out = StdCommand::new("launchctl")
   167→            .args(["load", "-w"])
   168→            .arg(&dest)
   169→            .output()?;
   170→        if out.status.success() {
   171→            println!("✓ loaded {}", label);
   172→        } else {
   173→            let err = String::from_utf8_lossy(&out.stderr);
   174→            eprintln!("⚠ load {}: {}", label, err.trim());
   175→        }
   176→    }
   177→
   178→    // Icons watcher: default on, same lifecycle as factory
   179→    if cfg!(target_os = "macos") {
   180→        match cmd_icons_install(cards_root) {
   181→            Ok(_) => {}
   182→            Err(e) => eprintln!("⚠ icon watcher: {}", e),
   183→        }
   184→    }
   185→
   186→    // Zellij plugin
   187→    let wasm_src = zellij_plugin_src(&repo_root);
   188→    if wasm_src.exists() {
   189→        let dest = zellij_plugin_dest();
   190→        if let Some(parent) = dest.parent() {
   191→            let _ = fs::create_dir_all(parent);
   192→        }
   193→        match fs::copy(&wasm_src, &dest) {
   194→            Ok(_) => println!("✓ zellij plugin installed: {}", dest.display()),
   195→            Err(e) => eprintln!("  zellij plugin copy failed: {}", e),
   196→        }
   197→    } else {
   198→        println!(
   199→            "  (zellij plugin wasm not built — skipping)\n  build with: cargo build --manifest-path crates/bop-zellij-plugin/Cargo.toml --target wasm32-wasip1 --release"
   200→        );
   201→    }
   202→
   203→    println!("\nFactory services installed. Run `bop factory status` to verify.");
   204→    Ok(())
   205→}
